@app.route("/evalcode")
def eval_code():
    code = request.values.get('code')
    if not code:
        return "Missing code parameter", 400
    try:
        # Restrict to expression evaluation only
        compiled = compile(code, '<string>', 'eval')
    except Exception as e:
        return f"Compilation error: {str(e)}", 400
    try:
        # Use a restricted environment with no builtins
        result = eval(compiled, {"__builtins__": {}})
        return str(result), 200
    except Exception as e:
        return f"Execution error: {str(e)}", 500

