import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_data = decoded.decode('utf-8')
        token = json.loads(token_data)
    except (base64.binascii.Error, ValueError, TypeError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None
